@app.post("/v1/models/upload", response_model=UploadResponse)
async def upload_model(
    file: UploadFile = File(...),
    x_tenant_id: Optional[str] = Header(default=None, convert_underscores=False),
):
    tenant_id = _get_tenant_id(x_tenant_id)

    if not file.filename:
        raise HTTPException(status_code=400, detail="Missing filename")

    data = _read_limited(file, MAX_UPLOAD_BYTES)
    sha = _sha256_bytes(data)
    model_id = uuid.uuid4().hex

    pkl_path = _model_path(tenant_id, model_id)
    meta_path = _meta_path(tenant_id, model_id)

    meta = {
        "tenant_id": tenant_id,
        "model_id": model_id,
        "filename": file.filename,
        "bytes": len(data),
        "sha256": sha,
        "created_at": _now(),
    }

    _write_atomic(pkl_path, data)
    _write_json_atomic(meta_path, meta)

    with _lock:
        _model_cache.pop((tenant_id, model_id), None)

    return UploadResponse(**meta)


@app.get("/v1/models/{model_id}", response_model=ModelInfo)
def get_model_info(
    model_id: str,
    x_tenant_id: Optional[str] = Header(default=None, convert_underscores=False),
):
    tenant_id = _get_tenant_id(x_tenant_id)
    meta_path = _meta_path(tenant_id, model_id)
    if not os.path.exists(meta_path):
        raise HTTPException(status_code=404, detail="Model not found")
    meta = _read_json(meta_path)
    with _lock:
        entry = _model_cache.get((tenant_id, model_id))
        meta["last_loaded_at"] = entry.loaded_at if entry else None
    return ModelInfo(**meta)


@app.delete("/v1/models/{model_id}")
def delete_model(
    model_id: str,
    x_tenant_id: Optional[str] = Header(default=None, convert_underscores=False),
):
    tenant_id = _get_tenant_id(x_tenant_id)
    pkl_path = _model_path(tenant_id, model_id)
    meta_path = _meta_path(tenant_id, model_id)

    removed = False
    for path in (pkl_path, meta_path):
        if os.path.exists(path):
            try:
                os.remove(path)
                removed = True
            except OSError:
                pass

    with _lock:
        _model_cache.pop((tenant_id, model_id), None)

    if not removed:
        raise HTTPException(status_code=404, detail="Model not found")
    return {"deleted": True, "tenant_id": tenant_id, "model_id": model_id}


@app.post("/v1/models/{model_id}:predict", response_model=PredictResponse)
def predict(
    model_id: str,
    req: PredictRequest,
    x_tenant_id: Optional[str] = Header(default=None, convert_underscores=False),
):
    tenant_id = _get_tenant_id(x_tenant_id)
    method = (req.method or "predict").strip()

    t0 = _now()
    model, from_cache = _get_model(tenant_id, model_id)
    out = _call_model(model, method, req.inputs, req.kwargs)
    latency_ms = (_now() - t0) * 1000.0

    try:
        json.dumps(out, default=str)
        output = out
    except TypeError:
        output = json.loads(json.dumps(out, default=str))

    return PredictResponse(
        tenant_id=tenant_id,
        model_id=model_id,
        method=method,
        output=output,
        loaded_from_cache=from_cache,
        latency_ms=latency_ms,
    )


